select

from mycase_case_backup
where case_id = #{caseId,jdbcType=BIGINT} and is_delete = 0

  and gmt_created >= #{beginTime,jdbcType=TIMESTAMP}


  and gmt_created <= #{endTime,jdbcType=TIMESTAMP}

order by id desc

select count(1) as casenum from mycase_case_backup where case_id = #{caseId,jdbcType=BIGINT} and is_delete = 0
and gmt_created >= #{beginTime,jdbcType=TIMESTAMP}
and gmt_created <= #{endTime,jdbcType=TIMESTAMP}
order by id desc

mapper.delete:
--     delete from mycase_case_backup where `gmt_created` < DATE_SUB(NOW(), INTERVAL 5 day)

    DELETE mycase_case_backup
      FROM mycase_case_backup
      JOIN (
      SELECT id
      FROM (
      SELECT id, case_id, gmt_created,
      @row_num := IF(@prev_case_id = case_id, @row_num + 1, 1) AS row_num,
      @prev_case_id := case_id
      FROM mycase_case_backup, (SELECT @row_num := 0, @prev_case_id := NULL) AS vars
      WHERE gmt_created < (NOW() - INTERVAL 5 DAY)
      ORDER BY case_id, gmt_created DESC
      ) AS temp_table
      WHERE row_num > 10
    ) AS deletions ON mycase_case_backup.id = deletions.id;
